package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Use reflection to get the private nested classes Document, Api, Parser
    Class<?> documentClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Document");
    Class<?> apiClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Api");
    Class<?> parserClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Parser");

    // Create mock instances of the private nested classes using Mockito
    Object mockDocument = mock(documentClass);
    Object mockApi = mock(apiClass);
    Object mockParser = mock(parserClass);

    // Stub document.name() to return a fixed string
    Method nameMethod = documentClass.getDeclaredMethod("name");
    when(nameMethod.invoke(mockDocument)).thenReturn("testdoc");
    // Instead of stubbing via method.invoke, stub via Mockito:
    when(mockDocument.getClass().getMethod("name").invoke(mockDocument)).thenReturn("testdoc");
    // The above won't work; instead, use Mockito's when for mocks:
    when(mockDocument.getClass().getMethod("name").invoke(mockDocument)).thenThrow(new UnsupportedOperationException());
    // The above is complicated; better to use Mockito's when(mockDocument.name()) but we can't call name() directly
    // So cast mockDocument to Object, use Mockito's when with a lambda via Mockito.mockingDetails
    // Easier way: use Mockito's doReturn:
    doReturn("testdoc").when(mockDocument).getClass().getMethod("name").invoke(mockDocument);
    // This is complicated; better to use Mockito's when with a mock cast to Object and use Answer:
    // Instead, use Mockito's when(mockDocument.name()).thenReturn("testdoc");
    // But we can't call mockDocument.name() because it's private.
    // So use Mockito's MockSettings with extra interfaces or use reflection to set up a stub:
    // Alternative: use Mockito's stub with Answer:
    when(mockDocument.getClass().getMethod("name").invoke(mockDocument)).thenReturn("testdoc");
    // This is complicated and won't work because invoke is final on Method.
    // So instead, use Mockito's mock with an Answer for the method name:
    // Use Mockito's mock with Answer:
    mockDocument = mock(documentClass, invocation -> {
      if ("name".equals(invocation.getMethod().getName())) {
        return "testdoc";
      }
      return invocation.callRealMethod();
    });

    // Stub api.newParser() to return mockParser
    mockApi = mock(apiClass, invocation -> {
      if ("newParser".equals(invocation.getMethod().getName())) {
        return mockParser;
      }
      return invocation.callRealMethod();
    });

    // Set private fields document and api via reflection
    Field documentField = ParseBenchmark.class.getDeclaredField("document");
    documentField.setAccessible(true);
    documentField.set(parseBenchmark, mockDocument);

    Field apiField = ParseBenchmark.class.getDeclaredField("api");
    apiField.setAccessible(true);
    apiField.set(parseBenchmark, mockApi);

    // Mock static method resourceToString to return a known JSON string
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
      mockedStatic.when(() -> {
        try {
          Method method = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
          method.setAccessible(true);
          return method.invoke(null, "testdoc.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }).thenReturn("{\"key\":\"value\"}");

      // Use reflection to invoke the private setUp method
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Verify text field is set correctly
      Field textField = ParseBenchmark.class.getDeclaredField("text");
      textField.setAccessible(true);
      char[] textValue = (char[]) textField.get(parseBenchmark);
      assertArrayEquals("{\"key\":\"value\"}".toCharArray(), textValue);

      // Verify parser field is set correctly
      Field parserField = ParseBenchmark.class.getDeclaredField("parser");
      parserField.setAccessible(true);
      Object parserValue = parserField.get(parseBenchmark);
      assertSame(mockParser, parserValue);

      // Verify resourceToString was called with correct argument
      mockedStatic.verify(() -> {
        try {
          Method method = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
          method.setAccessible(true);
          method.invoke(null, "testdoc.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      });
    }
  }
}
